examples.original_ir:
define double @test_mismatched_zeros(double %x) {
  %cmp = fcmp olt double %x, 0.000000e+00
  %sel = select i1 %cmp, double -0.000000e+00, double %x
  ret double %sel
}

examples.optimized_ir:
define double @test_mismatched_zeros(double %x) {
  %cmp = fcmp ole double %x, -0.000000e+00
  %sel = select i1 %cmp, double -0.000000e+00, double %x
  ret double %sel
}
